function validate(args, output) {
    const nums = args[0];
    const a = nums.slice().sort((x, y) => x - y);
    const b = output.slice().sort((x, y) => x - y);
    if (a.length !== b.length || !a.every((v, i) => v === b[i])) return false;
    let seenOdd = false;
    for (const x of output) {
        if (Math.abs(x % 2) === 1) {
            seenOdd = true;
        } else if (seenOdd) {
            return false;
        }
    }
    return true;
}

